    "            /* Mode 6 KPASS: msg = salt_buf (global). Same M[i>>2] |= v\n"
    "             * pattern; only the source pointer changes. */\n"
    "            if (mlen <= 55) {\n"
    "                for (int i = 0; i < 16; i++) hm[i] = 0;\n"
    "                for (int i = 0; i < mlen; i++) {\n"
    "                    uint v = (uint)salt_buf[i];\n"
    "                    hm[i >> 2] |= v << ((i & 3) * 8);\n"
    "                }\n"
    "                hm[mlen >> 2] |= (uint)0x80u << ((mlen & 3) * 8);\n"
    "                hm[14] = (uint)(64 + mlen) * 8u;\n"
    "                md5_block(&ihx, &ihy, &ihz, &ihw, hm);\n"
    "            } else {\n"
    "                int copy1 = (mlen < 64) ? mlen : 64;\n"
    "                for (int i = 0; i < 16; i++) hm[i] = 0;\n"
    "                for (int i = 0; i < copy1; i++) {\n"
    "                    uint v = (uint)salt_buf[i];\n"
    "                    hm[i >> 2] |= v << ((i & 3) * 8);\n"
    "                }\n"
    "                if (mlen < 64) hm[mlen >> 2] |= (uint)0x80u << ((mlen & 3) * 8);\n"
    "                md5_block(&ihx, &ihy, &ihz, &ihw, hm);\n"
    "                int rem = mlen - 64;\n"
    "                for (int i = 0; i < 16; i++) hm[i] = 0;\n"
    "                if (rem > 0) {\n"
    "                    for (int i = 0; i < rem; i++) {\n"
    "                        uint v = (uint)salt_buf[64 + i];\n"
    "                        hm[i >> 2] |= v << ((i & 3) * 8);\n"
    "                    }\n"
    "                }\n"
    "                if (mlen >= 64) {\n"
    "                    int p = (rem > 0) ? rem : 0;\n"
    "                    hm[p >> 2] |= (uint)0x80u << ((p & 3) * 8);\n"
    "                }\n"
    "                hm[14] = (uint)(64 + mlen) * 8u;\n"
    "                md5_block(&ihx, &ihy, &ihz, &ihw, hm);\n"
    "            }\n"
    "        }\n"
    "\n"
    "        /* Step 3: outer = MD5((key ^ opad) || inner_hash). The inner_hash\n"
    "         * is 16 bytes (4 uints) at hm[0..3] semantics; we use a fresh hop[]\n"
    "         * to avoid byte-cast aliasing (same rationale as Step 2). */\n"
    "        uint hop[16];\n"
    "        for (int i = 0; i < 16; i++)\n"
    "            hop[i] = key_block[i] ^ 0x5c5c5c5cu;\n"
    "        uint ohx = 0x67452301u, ohy = 0xEFCDAB89u,\n"
    "             ohz = 0x98BADCFEu, ohw = 0x10325476u;\n"
    "        md5_block(&ohx, &ohy, &ohz, &ohw, hop);\n"
    "\n"
    "        for (int i = 0; i < 16; i++) hop[i] = 0;\n"
    "        hop[0] = ihx; hop[1] = ihy; hop[2] = ihz; hop[3] = ihw;\n"
    "        hop[4] = 0x80u;          /* 0x80 at byte 16 = LE byte 0 of word 4 */\n"
    "        hop[14] = (64u + 16u) * 8u; /* 640 bits */\n"
    "        md5_block(&ohx, &ohy, &ohz, &ohw, hop);\n"
    "\n"
    "        st->h[0] = ohx;\n"
    "        st->h[1] = ohy;\n"
    "        st->h[2] = ohz;\n"
    "        st->h[3] = ohw;\n"
    "        return;\n"
    "    }\n"
    "\n"
    "    while (len - pos >= HASH_BLOCK_BYTES) {\n"
    "        for (int j = 0; j < 16; j++) {\n"
    "            int b = pos + j * 4;\n"
    "            M[j] = (uint)data[b]\n"
    "                 | ((uint)data[b + 1] << 8)\n"
    "                 | ((uint)data[b + 2] << 16)\n"
    "                 | ((uint)data[b + 3] << 24);\n"
    "        }\n"
    "        md5_block(&h0, &h1, &h2, &h3, M);\n"
    "        pos += HASH_BLOCK_BYTES;\n"
    "    }\n"
    "\n"
    "    int rem = len - pos;\n"
    "    for (int j = 0; j < 16; j++) M[j] = 0;\n"
    "    for (int i = 0; i < rem; i++) {\n"
    "        uint v = (uint)data[pos + i];\n"
    "        M[i >> 2] |= v << ((i & 3) * 8);\n"
    "    }\n"
    "    M[rem >> 2] |= (uint)0x80 << ((rem & 3) * 8);\n"
    "\n"
    "    if (rem < 56) {\n"
    "        M[14] = (uint)(len * 8);\n"
    "        M[15] = 0;\n"
    "        md5_block(&h0, &h1, &h2, &h3, M);\n"
    "    } else {\n"
    "        md5_block(&h0, &h1, &h2, &h3, M);\n"
    "        for (int j = 0; j < 16; j++) M[j] = 0;\n"
    "        M[14] = (uint)(len * 8);\n"
    "        M[15] = 0;\n"
    "        md5_block(&h0, &h1, &h2, &h3, M);\n"
    "    }\n"
    "\n"
    "    /* Step 2: hex-encode digest1 into M[] per params.algo_mode. Reuses the\n"
    "     * canonical md5_to_hex_{lc,uc} helpers from gpu_common.cl —\n"
    "     * those are byte-exact-validated by the existing e31 path. Modes 2/3\n"
    "     * post-process the bytes after the canonical encode, so they inherit\n"
    "     * the same byte-order convention.\n"
    "     * Result length (`inner_len`) is 32 chars for modes 0/1/2; 16 chars\n"
    "     * for mode 3; 64 chars for mode 4 (the full 64-byte intermediate is\n"
    "     * built here from salt-hex + pass-hex).\n"
    "     * Note: M[0..7] is unconditionally overwritten by every mode body\n"
    "     * (modes 0/1/2/3 via md5_to_hex_*; mode 4 via the byte-wise salt copy\n"
    "     * `mb[0..31] = salt_buf[0..31]`). Only M[8..15] needs zeroing for the\n"
    "     * downstream salt-append + 0x80 + padding path. Saves 8 stores per\n"
    "     * call vs the prior `for (j = 0; j < 16)` loop. */\n"
    "    for (int j = 8; j < 16; j++) M[j] = 0;\n"
    "    uint inner_len;\n"
    "    if (algo_mode == 1u) {\n"
    "        /* e350 MD5UCSALT: uppercase hex, forward order. */\n"
    "        md5_to_hex_uc(h0, h1, h2, h3, M);\n"
    "        inner_len = 32u;\n"
    "    } else if (algo_mode == 2u) {\n"
    "        /* e541 MD5revMD5SALT: lowercase hex, REVERSED character order across the\n"
    "         * full 32-char string. CPU prmd5REV at mdxfind.c:4160-4170 reverses\n"
    "         * the entire 32-char output relative to forward prmd5. Strategy:\n"
    "         * canonical encode then bytewise reverse M[0..31]. */\n"
    "        md5_to_hex_lc(h0, h1, h2, h3, M);\n"
    "        uchar *mb = (uchar *)M;\n"
    "        for (int i = 0; i < 16; i++) {\n"
    "            uchar t = mb[i];\n"
    "            mb[i] = mb[31 - i];\n"
    "            mb[31 - i] = t;\n"
    "        }\n"
    "        inner_len = 32u;\n"
    "    } else if (algo_mode == 3u) {\n"
    "        /* e542 MD5sub8_24SALT: lowercase hex, slice [8:24] = middle 16 chars.\n"
    "         * CPU at mdxfind.c:22055-22059: prmd5(...,32) then memcpy(mdbuf, mdbuf+8, 16).\n"
    "         * Strategy: canonical encode → copy bytes [8:24] down to [0:16] →\n"
    "         * zero bytes [16:32] (the post-encode tail) so the subsequent salt\n"
    "         * append + 0x80 marker land in clean memory. Without the zero-fill,\n"
    "         * mb[16..31] retains original hex chars 16..31 from the canonical\n"
    "         * encode and contaminates the outer MD5 input past the salt+0x80. */\n"
    "        md5_to_hex_lc(h0, h1, h2, h3, M);\n"
    "        uchar *mb = (uchar *)M;\n"
    "        for (int i = 0; i < 16; i++) mb[i] = mb[8 + i];\n"
    "        M[4] = 0u; M[5] = 0u; M[6] = 0u; M[7] = 0u;\n"
    "        inner_len = 16u;\n"
    "    } else if (algo_mode == 4u) {\n"
    "        /* e367 MD5_MD5SALTMD5PASS: outer MD5 over the 64-byte intermediate\n"
    "         * (hex32(MD5(salt)) || hex32(MD5(pass))). The CPU path at\n"
    "         * mdxfind.c:17027-17075 builds linebuf[0..63] with salt-hex at\n"
    "         * [0..31] and pass-hex at [32..63], then mymd5(linebuf, 64).\n"
    "         *\n"
    "         * Strategy:\n"
    "         *   1. Pass-hex: lowercase canonical encode of digest1 into M[8..15]\n"
    "         *      (bytes [32..63] of the message buffer).\n"
    "         *   2. Salt-hex: pre-computed by host as saltsnap[si].hashsalt and\n"
    "         *      packed into salt_buf by gpujob_opencl.c gpu_pack_salts when\n"
    "         *      use_hashsalt=1 (already wired for JOB_MD5_MD5SALTMD5PASS).\n"
    "         *      Copy the 32 bytes from salt_buf[0..31] into M[0..7]\n"
    "         *      (bytes [0..31] of the message buffer).\n"
    "         *   3. inner_len = 64; the host packed salt slot has the hashsalt\n"
    "         *      at offset 0 (slen field will be set to 32 by gpu_pack_salts\n"
    "         *      because hashlen=32), but the salt has ALREADY been consumed\n"
    "         *      into M[0..7] above — the step-3 outer block must NOT append\n"
    "         *      the salt a second time. We override slen=0 below; this\n"
    "         *      forces total_len=64 (>= 56) into the else branch, where\n"
    "         *      first_chunk=64-64=0 and the salt-append loop is a no-op. */\n"
    "        md5_to_hex_lc(h0, h1, h2, h3, &M[8]);\n"
    "        uchar *mb = (uchar *)M;\n"
    "        for (int i = 0; i < 32; i++) mb[i] = salt_buf[i];\n"
    "        inner_len = 64u;\n"
    "    } else {\n"
    "        /* mode 0 (default): e31 MD5SALT, lowercase hex, forward order. */\n"
    "        md5_to_hex_lc(h0, h1, h2, h3, M);\n"
    "        inner_len = 32u;\n"
    "    }\n"
    "\n"
    "    /* Step 3: outer MD5 over (hex_inner || salt). */\n"
    "    /* B6.8 (2026-05-06): mode 4 (e367) consumed the salt-hex into M[0..7]\n"
    "     * during step 2 — the message buffer is the COMPLETE 64-byte input,\n"
    "     * no outer salt append. Override slen=0 to short-circuit the\n"
    "     * salt-append loop in the else branch below: total_len=64+0=64\n"
    "     * (>=56) routes to the else branch; first_chunk = 64-64 = 0; both\n"
    "     * salt-append loops become no-ops; the first md5_block hashes M[]\n"
    "     * exactly as packed; the second block writes 0x80 at M[0] + length\n"
    "     * 512 bits at M[14]. Modes 0/1/2/3 are unaffected (slen unchanged). */\n"
    "    if (algo_mode == 4u) slen = 0u;\n"
    "    uint total_len = inner_len + slen;\n"
    "    if (total_len < 56u) {\n"
    "        /* Salt + 0x80 packed via salt_pack_uint. */\n"
    "        salt_pack_uint(M, inner_len >> 2, salt_buf, slen, /*use_eom=*/1u);\n"
    "        M[14] = total_len * 8u;\n"
    "        M[15] = 0u;\n"
    "        st->h[0] = 0x67452301u;\n"
    "        st->h[1] = 0xEFCDAB89u;\n"
    "        st->h[2] = 0x98BADCFEu;\n"
    "        st->h[3] = 0x10325476u;\n"
    "        md5_block(&st->h[0], &st->h[1], &st->h[2], &st->h[3], M);\n"
    "    } else {\n"
    "        uint first_chunk = 64u - inner_len;\n"
    "        if (first_chunk > slen) first_chunk = slen;\n"
    "        /* Salt-only pack for the first md5_block; 0x80 lives in the second\n"
    "         * block (added via OR-update at rem_salt path below). */\n"
    "        salt_pack_uint(M, inner_len >> 2, salt_buf, first_chunk, /*use_eom=*/0u);\n"
    "        st->h[0] = 0x67452301u;\n"
    "        st->h[1] = 0xEFCDAB89u;\n"
    "        st->h[2] = 0x98BADCFEu;\n"
    "        st->h[3] = 0x10325476u;\n"
    "        md5_block(&st->h[0], &st->h[1], &st->h[2], &st->h[3], M);\n"
    "\n"
    "        for (int j = 0; j < 16; j++) M[j] = 0;\n"
    "        uint rem_salt = slen - first_chunk;\n"
    "        for (uint i = 0; i < rem_salt; i++) {\n"
    "            uchar c = salt_buf[first_chunk + i];\n"
    "            M[i >> 2] |= ((uint)c) << ((i & 3) * 8);\n"
    "        }\n"
    "        M[rem_salt >> 2] |= ((uint)0x80u) << ((rem_salt & 3) * 8);\n"
    "        if (rem_salt < 56u) {\n"
    "            M[14] = total_len * 8u;\n"
    "            M[15] = 0u;\n"
    "            md5_block(&st->h[0], &st->h[1], &st->h[2], &st->h[3], M);\n"
    "        } else {\n"
    "            md5_block(&st->h[0], &st->h[1], &st->h[2], &st->h[3], M);\n"
    "            for (int j = 0; j < 16; j++) M[j] = 0;\n"
    "            M[14] = total_len * 8u;\n"
    "            M[15] = 0u;\n"
    "            md5_block(&st->h[0], &st->h[1], &st->h[2], &st->h[3], M);\n"
    "        }\n"
    "    }\n"
    "}\n"
    "\n"
    "/* template_pre_salt: compute the password-only portion ONCE per\n"
    " * (word, rule, mask, salt_chunk). For algo_mode 0 (e31) this is the\n"
    " * lowercase 32-char hex encoding of MD5(password). All other modes set\n"
    " * the sentinel for fallback handling in template_finalize_post.\n"
    " *\n"
    " * 2026-05-09 lane-batch experiment: only mode 0 is hoisted; modes 1-6\n"
    " * remain on the legacy template_finalize per-salt computation. */\n"
    "static inline void template_pre_salt(const uchar *data, int len,\n"
    "                                     uint algo_mode,\n"
    "                                     template_pre_salt_state *pre)\n"
    "{\n"
    "    if (algo_mode != 0u) {\n"
    "        pre->inner_len = TEMPLATE_PRE_SALT_SENTINEL;\n"
    "        return;\n"
    "    }\n"
    "\n"
    "    /* Mode 0 path: streaming MD5 of `data` followed by lowercase hex32\n"
    "     * encoding into pre->M[0..7]. Mirrors the inner-MD5+hex steps of\n"
    "     * the legacy template_finalize mode-0 branch (lines 378-479 in this\n"
    "     * core). */\n"
    "    uint Mi[16];\n"
    "    int pos = 0;\n"
    "    uint h0 = 0x67452301u, h1 = 0xEFCDAB89u,\n"
    "         h2 = 0x98BADCFEu, h3 = 0x10325476u;\n"
    "\n"
    "    while (len - pos >= HASH_BLOCK_BYTES) {\n"
    "        for (int j = 0; j < 16; j++) {\n"
    "            int b = pos + j * 4;\n"
    "            Mi[j] = (uint)data[b]\n"
    "                  | ((uint)data[b + 1] << 8)\n"
    "                  | ((uint)data[b + 2] << 16)\n"
    "                  | ((uint)data[b + 3] << 24);\n"
    "        }\n"
    "        md5_block(&h0, &h1, &h2, &h3, Mi);\n"
    "        pos += HASH_BLOCK_BYTES;\n"
    "    }\n"
    "\n"
    "    int rem = len - pos;\n"
    "    for (int j = 0; j < 16; j++) Mi[j] = 0;\n"
    "    for (int i = 0; i < rem; i++) {\n"
    "        uint v = (uint)data[pos + i];\n"
    "        Mi[i >> 2] |= v << ((i & 3) * 8);\n"
    "    }\n"
    "    Mi[rem >> 2] |= (uint)0x80 << ((rem & 3) * 8);\n"
    "\n"
    "    if (rem < 56) {\n"
    "        Mi[14] = (uint)(len * 8);\n"
    "        Mi[15] = 0;\n"
    "        md5_block(&h0, &h1, &h2, &h3, Mi);\n"
    "    } else {\n"
    "        md5_block(&h0, &h1, &h2, &h3, Mi);\n"
    "        for (int j = 0; j < 16; j++) Mi[j] = 0;\n"
    "        Mi[14] = (uint)(len * 8);\n"
    "        Mi[15] = 0;\n"
    "        md5_block(&h0, &h1, &h2, &h3, Mi);\n"
    "    }\n"
    "\n"
    "    /* Hex-encode digest1 into pre->M[0..7]. Same canonical helper as\n"
    "     * the legacy template_finalize mode 0 branch.\n"
    "     * Note: pre->M[0..7] is fully overwritten by md5_to_hex_lc (plain `=`\n"
    "     * stores in gpu_common.cl); only pre->M[8..15] needs zeroing for the\n"
    "     * downstream salt-append + 0x80 + padding path. Saves 8 stores per\n"
    "     * call vs the prior `for (j = 0; j < 16)` loop. */\n"
    "    for (int j = 8; j < 16; j++) pre->M[j] = 0;\n"
    "    md5_to_hex_lc(h0, h1, h2, h3, pre->M);\n"
    "    pre->inner_len = 32u;\n"
    "}\n"
    "\n"
    "/* template_finalize_post: runs ONCE per salt under the lane-batch\n"
    " * experiment. For algo_mode 0 (the only hoisted mode) it consumes\n"
    " * pre->M (the 32-char hex of MD5(password)) and computes the outer\n"
    " * MD5(hex32 || salt). For sentinel pre_state (any algo_mode != 0) it\n"
    " * dispatches to the legacy template_finalize, which handles the full\n"
    " * inner+outer per-salt computation. */\n"
    "static inline void template_finalize_post(template_state *st,\n"
    "                                          const template_pre_salt_state *pre,\n"
    "                                          const uchar *data, int len,\n"
    "                                          __global const uchar *salt_buf,\n"
    "                                          uint slen,\n"
    "                                          uint algo_mode)\n"
    "{\n"
    "    if (pre->inner_len == TEMPLATE_PRE_SALT_SENTINEL) {\n"
    "        /* Fallback: legacy template_finalize handles modes 1-6 + the full\n"
    "         * inner computation. Pass through buf+len unchanged. */\n"
    "        template_finalize(st, data, len, salt_buf, slen, algo_mode);\n"
    "        return;\n"
    "    }\n"
    "\n"
    "    /* Mode 0 hoisted path: pre->M[0..7] holds the 32-char lowercase hex\n"
    "     * of the inner MD5. Compute outer MD5(hex32 || salt) into st->h.\n"
    "     * Logic mirrors the \"Step 3: outer MD5\" block of the legacy mode-0\n"
    "     * template_finalize body verbatim — same total_len < 56 branch, same\n"
    "     * second-block fallback, same length-bits encoding. Only difference\n"
    "     * is M is initialised from pre->M instead of being freshly built. */\n"
    "    uint M[16];\n"
    "    for (int j = 0; j < 16; j++) M[j] = pre->M[j];\n"
    "    uint inner_len = pre->inner_len;\n"
    "\n"
    "    uint total_len = inner_len + slen;\n"
    "    if (total_len < 56u) {\n"
    "        /* Salt + 0x80 packed via salt_pack_uint. */\n"
    "        salt_pack_uint(M, inner_len >> 2, salt_buf, slen, /*use_eom=*/1u);\n"
    "        M[14] = total_len * 8u;\n"
    "        M[15] = 0u;\n"
    "        st->h[0] = 0x67452301u;\n"
    "        st->h[1] = 0xEFCDAB89u;\n"
    "        st->h[2] = 0x98BADCFEu;\n"
    "        st->h[3] = 0x10325476u;\n"
    "        md5_block(&st->h[0], &st->h[1], &st->h[2], &st->h[3], M);\n"
    "    } else {\n"
    "        uint first_chunk = 64u - inner_len;\n"
    "        if (first_chunk > slen) first_chunk = slen;\n"
    "        /* Salt-only pack; 0x80 lives in the second md5_block. */\n"
    "        salt_pack_uint(M, inner_len >> 2, salt_buf, first_chunk, /*use_eom=*/0u);\n"
    "        st->h[0] = 0x67452301u;\n"
    "        st->h[1] = 0xEFCDAB89u;\n"
    "        st->h[2] = 0x98BADCFEu;\n"
    "        st->h[3] = 0x10325476u;\n"
    "        md5_block(&st->h[0], &st->h[1], &st->h[2], &st->h[3], M);\n"
    "\n"
    "        for (int j = 0; j < 16; j++) M[j] = 0;\n"
    "        uint rem_salt = slen - first_chunk;\n"
    "        for (uint i = 0; i < rem_salt; i++) {\n"
    "            uchar c = salt_buf[first_chunk + i];\n"
    "            M[i >> 2] |= ((uint)c) << ((i & 3) * 8);\n"
    "        }\n"
    "        M[rem_salt >> 2] |= ((uint)0x80u) << ((rem_salt & 3) * 8);\n"
    "        if (rem_salt < 56u) {\n"
    "            M[14] = total_len * 8u;\n"
    "            M[15] = 0u;\n"
    "            md5_block(&st->h[0], &st->h[1], &st->h[2], &st->h[3], M);\n"
    "        } else {\n"
    "            md5_block(&st->h[0], &st->h[1], &st->h[2], &st->h[3], M);\n"
    "            for (int j = 0; j < 16; j++) M[j] = 0;\n"
    "            M[14] = total_len * 8u;\n"
    "            M[15] = 0u;\n"
    "            md5_block(&st->h[0], &st->h[1], &st->h[2], &st->h[3], M);\n"
    "        }\n"
    "    }\n"
    "}\n"
    "\n"
    "/* template_iterate: -i loop step. for x > 1, mdxfind iter feedback for JOB_MD5SALT is the lowercase hex of the prior 32-char digest re-hashed (mdxfind.c default `prmd5` at line 9706). The default HEX_FEEDBACK template_iterate matches this exactly. We REUSE the unsalted MD5 template_iterate — no per-iter salt re-application (matches CPU JOB_MD5SALT iter convention). */\n"
    "static inline void template_iterate(template_state *st)\n"
    "{\n"
    "    uint M[16];\n"
    "    md5_to_hex_lc(st->h[0], st->h[1], st->h[2], st->h[3], M);\n"
    "    M[8] = 0x80u;\n"
    "    for (int j = 9; j < 14; j++) M[j] = 0u;\n"
    "    M[14] = 32u * 8u;\n"
    "    M[15] = 0u;\n"
    "    st->h[0] = 0x67452301u;\n"
    "    st->h[1] = 0xEFCDAB89u;\n"
    "    st->h[2] = 0x98BADCFEu;\n"
    "    st->h[3] = 0x10325476u;\n"
    "    md5_block(&st->h[0], &st->h[1], &st->h[2], &st->h[3], M);\n"
    "}\n"
    "\n"
    "/* template_digest_compare: probe the compact table with the final digest. */\n"
    "static inline int template_digest_compare(\n"
    "    const template_state *st,\n"
    "    __global const uint *compact_fp, __global const uint *compact_idx,\n"
    "    ulong compact_mask, uint max_probe, uint hash_data_count,\n"
    "    __global const uchar *hash_data_buf, __global const ulong *hash_data_off,\n"
    "    __global const ulong *overflow_keys, __global const uchar *overflow_hashes,\n"
    "    __global const uint *overflow_offsets, uint overflow_count,\n"
    "    uint *out_idx)\n"
    "{\n"
    "    return probe_compact_idx(\n"
    "        st->h[0], st->h[1], st->h[2], st->h[3],\n"
    "        compact_fp, compact_idx,\n"
    "        compact_mask, max_probe, hash_data_count,\n"
    "        hash_data_buf, hash_data_off,\n"
    "        overflow_keys, overflow_hashes, overflow_offsets, overflow_count,\n"
    "        out_idx);\n"
    "}\n"
    "\n"
    "#define template_emit_hit(hits, hit_count, max_hits, st, widx, sidx, iter) \\\n"
    "    EMIT_HIT_4((hits), (hit_count), (max_hits), \\\n"
    "               (widx), (sidx), (iter), \\\n"
    "               (st)->h[0], (st)->h[1], (st)->h[2], (st)->h[3])\n"
    "\n"
    "#define template_emit_hit_or_overflow(hits, hit_count, max_hits, st, widx, sidx, iter, \\\n"
    "                                      hashes_shown, matched_idx, dedup_mask, \\\n"
    "                                      ovr_set, ovr_gid, lane_gid) \\\n"
    "    EMIT_HIT_4_DEDUP_OR_OVERFLOW((hits), (hit_count), (max_hits), \\\n"
    "               (widx), (sidx), (iter), \\\n"
    "               (st)->h[0], (st)->h[1], (st)->h[2], (st)->h[3], \\\n"
    "               (hashes_shown), (matched_idx), (dedup_mask), \\\n"
    "               (ovr_set), (ovr_gid), (lane_gid))\n"
;
